// src/pages/StudentDashboard.jsx
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Loader2 } from 'lucide-react';
import Chatbot from '../chatbot/chatbot'; // keep if you have this component

const StudentDashboard = () => {
  const [payload, setPayload] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [showAllSemesters, setShowAllSemesters] = useState(false);

  useEffect(() => {
    loadDashboard();
    // eslint-disable-next-line
  }, []);

  const loadDashboard = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await axios.get('http://localhost:65000/api/students/getStudentDashboard', {
        withCredentials: true
      });
      setPayload(res.data);
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || 'Failed to load data');
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="loader-container">
        <Loader2 className="loader-icon" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="error-box">
        <h3>Error</h3>
        <p>{error}</p>
        <button onClick={loadDashboard}>Retry</button>
      </div>
    );
  }

  if (!payload) {
    return <p>No data returned from API.</p>;
  }

  const { student, academicProgress } = payload;
  const current = academicProgress.currentSemesterDetails || {};
  const percentProgress = Math.min(
    100,
    Math.round((academicProgress.totalCreditsEarned / Math.max(1, academicProgress.totalCreditsRequired)) * 100)
  );

  return (
    <div className="dashboard-root">
      <Chatbot />

      <header className="top-header">
        <div className="student-left">
          <div className="avatar">
            {student.photoPath ? (
              <img src={`http://localhost:65000/${student.photoPath}`} alt="student" />
            ) : (
              <div className="initial">
                {student.name.fullName ? student.name.fullName.charAt(0).toUpperCase() : 'S'}
              </div>
            )}
          </div>
          <div>
            <h1>{student.name.fullName}</h1>
            <div className="sub">{student.studentId} • {student.departmentCode} {student.department}</div>
            <div className="sub small">{student.universityEmail} • {student.contactNumber}</div>
            <div className="badge">{student.degreeLevel} • {student.section}</div>
          </div>
        </div>

        <div className="right-stats">
          <div className="stat">
            <div className="label">Cumulative GPA</div>
            <div className="value">{academicProgress.cumulativeGPA ?? '-'}</div>
          </div>
          <div className="stat">
            <div className="label">Total Credits</div>
            <div className="value">{academicProgress.totalCreditsEarned}/{academicProgress.totalCreditsRequired}</div>
          </div>
          <div className="stat">
            <div className="label">Progress</div>
            <div className="value">{academicProgress.completionPercentage ?? percentProgress}%</div>
          </div>
        </div>
      </header>

      <section className="summary-cards">
        <div className="card">
          <h3>Degree Progress</h3>
          <div className="progress-line">
            <div className="fill" style={{ width: `${percentProgress}%` }} />
          </div>
          <div className="muted">Completed {academicProgress.totalCreditsEarned} of {academicProgress.totalCreditsRequired} credits</div>
          <div className="muted">Scholarship: {student.scholarship.isApplicant ? `${student.scholarship.percentage}%` : 'N/A'}</div>
        </div>

        <div className="card">
          <h3>Current Semester (#{academicProgress.currentSemester})</h3>
          <div className="metric-row">
            <div>
              <div className="metric-label">Semester GPA</div>
              <div className="metric-value">{current.semesterGPA ?? '-'}</div>
            </div>
            <div>
              <div className="metric-label">Credits Attempted</div>
              <div className="metric-value">{current.creditsAttempted ?? 0}</div>
            </div>
            <div>
              <div className="metric-label">Credits Earned</div>
              <div className="metric-value">{current.creditsEarned ?? 0}</div>
            </div>
            <div>
              <div className="metric-label">Quality Points</div>
              <div className="metric-value">{current.qualityPoints ?? 0}</div>
            </div>
          </div>
          <div className="muted">
            {current.startDate ? `Period: ${new Date(current.startDate).toLocaleDateString()} - ${new Date(current.endDate).toLocaleDateString()}` : ''}
          </div>
        </div>

        <div className="card">
          <h3>Quick Actions</h3>
          <div style={{display: 'flex', gap: 8}}>
            <button onClick={() => setShowAllSemesters(s => !s)} className="btn alt">{showAllSemesters ? 'Hide' : 'Show'} Semesters</button>
            <button onClick={loadDashboard} className="btn ghost">Refresh</button>
          </div>
        </div>
      </section>

      <section className="courses-section">
        <h2>Enrolled Courses - Current Semester</h2>
        <div className="courses-grid">
          { (current.courses || []).length === 0 && <div className="muted">No courses found for current semester.</div> }

          { (current.courses || []).map((c, idx) => (
            <div key={idx} className="course-card">
              <div className="course-top">
                <div>
                  <div className="course-code">{c.courseCode || '—'}</div>
                  <div className="course-name">{c.courseName || 'Untitled Course'}</div>
                </div>
                <div className="course-meta">
                  <div className={`status ${c.status?.toLowerCase()}`}>{c.status ?? 'N/A'}</div>
                  <div className="grade">{c.grade ?? '-'}</div>
                </div>
              </div>

              <div className="course-body">
                <div>Credits: <strong>{c.creditsEarned ?? 0}</strong></div>
                
              </div>
            </div>
          )) }
        </div>
      </section>

      { showAllSemesters && (
        <section className="semesters-section">
          <h2>All Semesters</h2>
          <div className="sem-table">
            <div className="row header">
              <div>Semester</div><div>Status</div><div>GPA</div><div>Credits</div><div>Period</div><div>Courses</div>
            </div>
            { (academicProgress.allSemesters || []).map((s, i) => (
              <div key={i} className="row">
                <div>{s.semesterNumber}</div>
                <div>{s.status}</div>
                <div>{s.semesterGPA}</div>
                <div>{s.creditsEarned}/{s.creditsAttempted}</div>
                <div>{s.startDate ? `${new Date(s.startDate).toLocaleDateString()} - ${new Date(s.endDate).toLocaleDateString()}` : '-'}</div>
                <div>
                  { (s.courses || []).map((cc, idx) => (
                    <div key={idx} className="mini-course">
                      <strong>{cc.courseCode}</strong> • {cc.courseName} • {cc.grade ?? '-'}
                    </div>
                  )) }
                </div>
              </div>
            )) }
          </div>
        </section>
      ) }

     

      {/* Styles */}
      <style>{`
        .dashboard-root { padding: 28px; font-family: Inter, system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue"; background: #f3f6fb; color: #0f172a; min-height: 100vh;}
        .top-header { display:flex; justify-content: space-between; align-items: center; gap: 20px; margin-bottom: 20px;}
        .student-left { display:flex; gap: 16px; align-items:center; }
        .avatar { width:96px; height:96px; border-radius:12px; overflow:hidden; background:#fff; display:flex; align-items:center; justify-content:center; box-shadow: 0 6px 20px rgba(15,23,42,0.06);}
        .avatar img { width:100%; height:100%; object-fit:cover; }
        .initial { font-size:34px; font-weight:700; color:#0b1220; }
        .top-header h1 { margin:0; font-size:20px; }
        .sub { color:#475569; margin-top:4px;}
        .sub.small { font-size:12px; color:#64748b; margin-top:6px;}
        .badge { margin-top:8px; background:#eef2ff; color:#3730a3; padding:6px 8px; display:inline-block; border-radius:8px; font-weight:600; font-size:13px; }

        .right-stats { display:flex; gap:12px; align-items:center; }
        .stat { background:#fff; padding:12px 16px; border-radius:10px; box-shadow: 0 4px 10px rgba(2,6,23,0.04); text-align:center; min-width:120px;}
        .stat .label { font-size:12px; color:#64748b; }
        .stat .value { font-weight:700; font-size:18px; margin-top:6px; }

        .summary-cards { display:grid; grid-template-columns: 1fr 1fr 320px; gap:16px; margin-bottom: 20px; }
        .card { background:#fff; padding:16px; border-radius:12px; box-shadow: 0 6px 16px rgba(2,6,23,0.04); }
        .progress-line { width:100%; height:12px; background:#eef2ff; border-radius:999px; overflow:hidden; margin:12px 0;}
        .progress-line .fill { height:100%; background:#2563eb; transition: width 0.8s ease; border-radius:999px; }

        .metric-row { display:flex; justify-content:space-between; gap:12px; margin-top:12px; }
        .metric-label { color:#475569; font-size:12px; }
        .metric-value { font-weight:700; font-size:18px; }

        .btn { padding:8px 12px; border-radius:8px; background:#2563eb; color:white; border:none; cursor:pointer; }
        .btn.alt { background:#10b981; }
        .btn.ghost { background:transparent; border:1px solid #e2e8f0; color:#0f172a; }

        .courses-section h2 { margin:0 0 12px 0; }
        .courses-grid { display:grid; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); gap:12px; }
        .course-card { background:#fff; padding:12px; border-radius:10px; border:1px solid #eef2ff; }
        .course-top { display:flex; justify-content:space-between; align-items:center; margin-bottom:8px; }
        .course-code { font-weight:700; color:#0f172a; }
        .course-name { color:#475569; margin-top:6px; }
        .course-meta { text-align:right; }
        .status { padding:6px 8px; border-radius:8px; font-size:12px; font-weight:700; display:inline-block;}
        .status.completed { background:#ecfeff; color:#065f46; }
        .status.enrolled { background:#eef2ff; color:#1e40af; }
        .status.dropped { background:#fff1f2; color:#9f1239; }
        .grade { font-weight:800; margin-top:8px; }

        .attendance-bar { height:10px; background:#f1f5f9; border-radius:999px; overflow:hidden; margin-top:8px; }
        .att-fill { height:100%; background:#10b981; transition: width 0.9s ease;}

        .sem-table { background:#fff; padding:12px; border-radius:10px; margin-top:10px; }
        .row { display:grid; grid-template-columns: 60px 90px 80px 120px 220px 1fr; gap:12px; padding:8px 10px; align-items:center; border-bottom:1px solid #f1f5f9; }
        .row.header { font-weight:700; color:#0f172a; background:#f8fafc; border-bottom:1px solid #e6eefc; }
        .mini-course { font-size:13px; color:#475569; margin-bottom:6px; }

        .raw-section .raw { max-height:340px; overflow:auto; background:#0b1220; color:#e6eefc; padding:10px; border-radius:8px; }

        .loader-container { height:100vh; display:flex; align-items:center; justify-content:center; }
        .loader-icon { width:56px; height:56px; color:#2563eb; animation: spin 1s linear infinite; }
        @keyframes spin { from{ transform:rotate(0);} to{ transform:rotate(360deg);} }

        .error-box { padding:20px; border-radius:12px; background:#fff1f2; color:#9f1239; margin:20px; }
      `}</style>
    </div>
  );
};

export default StudentDashboard;
